INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fd567a92-ed32-4bf5-a504-5aa5d020f428',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Custom Layers — Building Reusable Modules with Layer Subclassing$escape$,
  $escape$Keras's `Layer` base class is the atomic unit of model architecture. When built-in layers fall short, subclassing gives you full control over weights, forward logic, and serialization. Override `build()` to create weights lazily (they're initialized on first call, so input shape is known), and `call()` to define the forward pass. This keeps weight creation separate from computation — critical for proper shape inference and saving.

Activation functions live in `keras.activations` (functional) or as layer objects via `keras.layers.Activation`. For custom activations inside a layer, call them directly: `keras.activations.gelu(x)`. Prefer the functional form inside `call()` to avoid nesting layer objects unnecessarily.

For composed modules — groups of layers acting as one — subclass `Layer` and instantiate child layers in `__init__`, not `build()`. This ensures sublayers are tracked for `layer.trainable_weights` and `model.summary()`. Use `self.supports_masking = True` if your layer must propagate masks through sequence models.$escape$,
  $escape$import keras

class GatedDenseBlock(keras.Layer):
    def __init__(self, units, **kwargs):
        super().__init__(**kwargs)
        self.dense = keras.layers.Dense(units)
        self.gate  = keras.layers.Dense(units, activation="sigmoid")
        self.norm  = keras.layers.LayerNormalization()

    def build(self, input_shape):
        # Sublayer weights are built on first call automatically;
        # declare any *direct* weights here if needed.
        super().build(input_shape)

    def call(self, x, training=False):
        h = keras.activations.gelu(self.dense(x))
        g = self.gate(x)
        return self.norm(h * g)

# Usage
block = GatedDenseBlock(128)
model = keras.Sequential([keras.layers.Input((64,)), block, keras.layers.Dense(10)])
model.summary()$escape$,
  $escape$python$escape$,
