INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'afc01fa7-66fe-4bbd-a5f6-b0fcefeb6047',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras GPU Acceleration — CUDA Devices, Mixed Precision, and What Actually Speeds Up Training$escape$,
  $escape$Keras 3 abstracts device placement through `keras.device()` context managers. To run ops on GPU, wrap your forward pass or model build in `with keras.device('cuda:0'):`. For multi-GPU setups, use `keras.distribution.DataParallel` with a `DeviceMesh`. Tensors are created on the device active at call time — unlike PyTorch, there's no `.to(device)` call; device is set contextually.

Mixed precision is the highest-ROI GPU optimization in Keras. Enable it globally with `keras.mixed_precision.set_global_policy('mixed_float16')` before model creation. Keras automatically keeps BatchNorm and softmax in float32 for numerical stability while running Dense and Conv layers in float16 — cutting VRAM usage roughly in half and doubling throughput on Ampere+ GPUs.

For the optimizer, Keras wraps it with a `LossScaleOptimizer` automatically when mixed precision is active, preventing float16 underflow during gradient updates. Check active policy mid-training with `keras.mixed_precision.global_policy()`. Avoid manual casting — let the policy handle dtype promotion across layers.$escape$,
  $escape$import keras

# Enable mixed precision globally (before model build)
keras.mixed_precision.set_global_policy('mixed_float16')

# Build model on specific CUDA device
with keras.device('cuda:0'):
    model = keras.Sequential([
        keras.layers.Dense(512, activation='relu'),
        keras.layers.Dense(10, activation='softmax')  # auto float32 for stability
    ])

# Optimizer is auto-wrapped with LossScaleOptimizer
model.compile(optimizer='adam', loss='sparse_categorical_crossentropy')

# Verify active policy
print(keras.mixed_precision.global_policy())  # <Policy "mixed_float16">$escape$,
  $escape$python$escape$,
