INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '614ecf3a-beee-42c9-b72e-c3e119e9f393',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Model Debugging — Gradient Flow, NaN Loss, and Exploding/Vanishing Gradients$escape$,
  $escape$NaN loss in Keras almost always traces to exploding gradients or bad input data. Start by adding `tf.debugging.check_numerics` inside a custom `tf.GradientTape` training step to pinpoint exactly which op produces the NaN. For gradient visibility, use `model.optimizer.get_gradients(loss, model.trainable_weights)` or log gradient norms with a custom `keras.callbacks.Callback` overriding `on_batch_end`.

Vanishing gradients in deep networks manifest as near-zero gradient norms in early layers — check per-layer with `tf.linalg.global_norm`. Common fixes: switch activation from `sigmoid` to `relu`/`gelu`, use `keras.initializers.HeNormal()` for weights, or add `BatchNormalization()` between dense layers.

For exploding gradients, `clipnorm` or `clipvalue` in the optimizer constructor is the fastest fix: `Adam(learning_rate=1e-3, clipnorm=1.0)`. If loss goes NaN on batch 1, suspect input preprocessing — add `tf.debugging.assert_all_finite(x_batch, 'Input contains NaN')` before the forward pass. Mixed precision (`tf.keras.mixed_precision.set_global_policy('mixed_float16')`) requires a `LossScaleOptimizer` wrapper to prevent underflow in float16 gradients.$escape$,
  $escape$import tensorflow as tf
import keras

# Gradient norm logging callback
class GradientNormLogger(keras.callbacks.Callback):
    def on_train_batch_end(self, batch, logs=None):
        with tf.GradientTape() as tape:
            # Recompute on a stored batch for inspection (use sparingly)
            pass

# Clip exploding gradients at optimizer level
optimizer = keras.optimizers.Adam(learning_rate=1e-3, clipnorm=1.0)

# Catch NaNs early in custom training loop
@tf.function
def train_step(x, y):
    tf.debugging.assert_all_finite(x, 'Input NaN detected')
    with tf.GradientTape() as tape:
        preds = model(x, training=True)
        loss = loss_fn(y, preds)
    tf.debugging.check_numerics(loss, 'Loss is NaN or Inf')
    grads = tape.gradient(loss, model.trainable_weights)
    norms = [tf.linalg.norm(g) for g in grads if g is not None]
    optimizer.apply_gradients(zip(grads, model.trainable_weights))
    return loss, norms$escape$,
  $escape$python$escape$,
