INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '219d52b2-898e-419f-a185-41e0defa7440',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Model Evaluation — Metrics, Confusion Matrix, and Cross-Validation$escape$,
  $escape$Choosing the right metrics in Keras starts at compile time. For binary classification, use `metrics=['accuracy', tf.keras.metrics.AUC(), tf.keras.metrics.Precision(), tf.keras.metrics.Recall()]`. For multi-class, swap in `tf.keras.metrics.SparseCategoricalAccuracy()` or `CategoricalAccuracy()` depending on whether labels are integers or one-hot. For regression tasks, `MeanAbsoluteError` and `RootMeanSquaredError` are your defaults.

Keras doesn't natively render confusion matrices — use `model.predict()` to get logits or probabilities, argmax them, then pass to `sklearn.metrics.confusion_matrix`. This decoupling is intentional: Keras owns the forward pass, sklearn owns the analysis.

For cross-validation, Keras integrates with `scikeras.wrappers.KerasClassifier` to slot into `sklearn.model_selection.StratifiedKFold`. Wrap your `build_model` fn, pass it to `cross_val_score`, and you get fold-level accuracy without manually managing train/val splits. Use `StratifiedKFold` for imbalanced datasets — it preserves class distribution across folds, which plain `KFold` won't.$escape$,
  $escape$import numpy as np
from sklearn.metrics import confusion_matrix
from sklearn.model_selection import StratifiedKFold, cross_val_score
from scikeras.wrappers import KerasClassifier
import tensorflow as tf

# Compile with task-specific metrics
model.compile(
    optimizer='adam',
    loss='sparse_categorical_crossentropy',
    metrics=[
        tf.keras.metrics.SparseCategoricalAccuracy(),
        tf.keras.metrics.AUC()
    ]
)

# Confusion matrix from predictions
y_pred = np.argmax(model.predict(X_test), axis=1)
cm = confusion_matrix(y_test, y_pred)

# Cross-validation via scikeras
def build_model():
    m = tf.keras.Sequential([tf.keras.layers.Dense(64, activation='relu'), tf.keras.layers.Dense(3, activation='softmax')])
    m.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return m

wrapped = KerasClassifier(model=build_model, epochs=10, batch_size=32, verbose=0)
scores = cross_val_score(wrapped, X, y, cv=StratifiedKFold(n_splits=5))
print(f"CV Accuracy: {scores.mean():.3f} ± {scores.std():.3f}")$escape$,
  $escape$python$escape$,
