INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53d742cb-47b1-464c-b0d1-c23f608735e6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras 3 + JAX — Using jit, grad, and vmap with Keras Models$escape$,
  $escape$Keras 3's JAX backend unlocks JAX's functional transforms, but Keras models are stateful objects — JAX requires pure functions. The bridge is `model.stateless_call(trainable_vars, non_trainable_vars, x)`, which separates weights from the forward pass so you can treat it as a pure function.

Wrap it in `jax.jit` and the XLA compiler fuses ops, eliminates redundant memory allocations, and generates device-optimized kernels — your first call traces and compiles, subsequent calls hit the cache. For differentiation, pass `stateless_call` into `jax.grad` targeting `trainable_vars`; gradients flow through Keras layers without a `GradientTape` in sight. `jax.vmap` vectorizes over a batch axis, letting you map a single-sample forward pass across a batch without writing explicit loops — useful for per-sample gradient computations or ensemble inference.

Note: `non_trainable_vars` (BatchNorm moving stats, etc.) must be threaded through manually since JAX transforms can't mutate state. `model.stateless_call` returns `(outputs, updated_non_trainable_vars)` — update them explicitly each step.$escape$,
  $escape$import jax
import jax.numpy as jnp
import keras

keras.backend.set_backend("jax")

model = keras.Sequential([
    keras.layers.Dense(64, activation="relu"),
    keras.layers.Dense(1),
])
model.build((None, 32))

def loss_fn(trainable_vars, non_trainable_vars, x, y):
    preds, _ = model.stateless_call(trainable_vars, non_trainable_vars, x)
    return jnp.mean((preds - y) ** 2)

grad_fn = jax.jit(jax.grad(loss_fn))  # XLA-compiled gradient

x = jnp.ones((8, 32))
y = jnp.ones((8, 1))
grads = grad_fn(model.trainable_variables, model.non_trainable_variables, x, y)$escape$,
  $escape$python$escape$,
