INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8f3ad6b9-ad34-4430-88b1-56d47dbae48e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Model Serialization — Choosing Between SavedModel, H5, and Keras v3$escape$,
  $escape$Keras offers three serialization formats, each with distinct trade-offs. The native `.keras` format (v3, introduced in Keras 3.x) is the recommended default — it saves the full model config, weights, and optimizer state in a single zip archive with zero TensorFlow coupling. Use `model.save('model.keras')` and `keras.saving.load_model('model.keras')`.

The legacy HDF5 format (`.h5`) still works but lacks support for custom layers with complex configs and is slower to load. Avoid it for new projects.

TensorFlow's SavedModel format (`model.save('saved_model_dir/')`) is required when serving via TensorFlow Serving or exporting to TFLite/TF.js. It serializes the computation graph, not just weights, making it backend-specific.

For mid-training checkpointing, use `keras.callbacks.ModelCheckpoint` with `save_best_only=True` and `monitor='val_loss'` to retain only the best epoch. Pair with `save_weights_only=True` when you only need weight restoration, cutting file size significantly. Always verify restoration with `model.predict` on a test sample before retraining.$escape$,
  $escape$import keras

# Save full model in native Keras v3 format
model.save('my_model.keras')

# Restore
loaded_model = keras.saving.load_model('my_model.keras')

# Mid-training checkpoint callback
checkpoint_cb = keras.callbacks.ModelCheckpoint(
    filepath='checkpoints/epoch_{epoch:02d}_val{val_loss:.4f}.keras',
    monitor='val_loss',
    save_best_only=True,
    save_weights_only=False,
)

model.fit(X_train, y_train, validation_data=(X_val, y_val), callbacks=[checkpoint_cb])

# Weights-only save/load (smaller file, no optimizer state)
model.save_weights('weights.weights.h5')
model.load_weights('weights.weights.h5')$escape$,
  $escape$python$escape$,
